// Helpers
export const getAllCategorySlugs = () => Object.keys(serviceCategories)

export const getAllSubpageParams = () => {
  const out = []
  for (const [catSlug, cat] of Object.entries(serviceCategories)) {
    for (const subSlug of Object.keys(cat.subpages || {})) {
      out.push({ category: catSlug, slug: subSlug })
    }
  }
  return out
}

export const getCategory = (slug) => serviceCategories[slug]

export const getSubpage = (catSlug, subSlug) => {
  const cat = serviceCategories[catSlug]
  if (!cat) return null
  const sub = cat.subpages?.[subSlug]
  if (!sub) return null

  // Location pages (icon: 'MapPin') carry unique city-specific overview text but
  // no city-specific features, benefits, faqs or industries. Inheriting those from
  // the parent category causes the rendered page to be ~80% identical to the parent,
  // which makes Google override the declared canonical with the parent URL (GSC:
  // "Duplicate, Google chose different canonical than user"). Fix: location pages
  // only use sections they explicitly define — they don't fall back to the parent.
  const isLocationPage = sub.icon === 'MapPin'

  return {
    ...cat,
    ...sub,
    parentName: cat.name,
    parentSlug: catSlug,
    benefits:   isLocationPage ? (sub.benefits   || null) : (sub.benefits   || cat.benefits),
    process:    isLocationPage ? (sub.process     || null) : (sub.process    || cat.process),
    industries: isLocationPage ? (sub.industries  || null) : (sub.industries || cat.industries),
    features:   isLocationPage ? (sub.features    || null) : (sub.features   || cat.features),
    faqs:       isLocationPage ? (sub.faqs        || null) : (sub.faqs       || cat.faqs),
  }
}

export const getRelatedServices = (currentCat, count = 3) => {
  const others = Object.entries(serviceCategories).filter(([s]) => s !== currentCat)
  return others.slice(0, count).map(([slug, c]) => ({ slug, name: c.name, short: c.short, icon: c.icon }))
}
